return await (async () => {
  const req = (url) => new Promise((resolve) => {
    const xhr = new XMLHttpRequest();
    xhr.open('GET', url);
    xhr.onload = () => resolve({ url, status: xhr.status, text: xhr.responseText });
    xhr.onerror = () => resolve({ url, status: xhr.status, text: 'error' });
    xhr.send();
  });
  const info = await req('/getInfo');
  const routers = await req('/getRouters');
  return { info, routers, installed: !!window.__repairMockInstalled, href: location.href };
})()
